from claude_agent_sdk import LLMClient
import json, hashlib

class ReplayLLM(LLMClient):
    def __init__(self, trace_path):
        self.events = [json.loads(l) for l in open(trace_path)
                       if json.loads(l)["class"] == "stubbable_llm"]
        self.idx = 0

    def call(self, messages, **_):
        prompt_hash = hashlib.sha1(json.dumps(messages).encode()).hexdigest()
        e = self.events[self.idx]
        if e["prompt_hash"][:8] != prompt_hash[:8]:
            raise ReplayMissError(f"event {self.idx}: prompt drift")
        self.idx += 1
        return {"completion": e["completion"], "tool_calls": e.get("tool_calls", [])}
